import json
from datetime import datetime
from typing import Any, Dict, List

import modal

app = modal.App("modal-event-pipeline")
image = modal.Image.debian_slim().pip_install("fastapi")

queue = modal.Queue.from_name("modal-event-pipeline-queue", create_if_missing=True)
volume = modal.Volume.from_name("modal-event-pipeline-vol", create_if_missing=True)
status_dict = modal.Dict.from_name("modal-event-pipeline-output", create_if_missing=True)

OUTPUT_PATH = "/events/processed_events.json"


def _generate_events() -> List[Dict[str, Any]]:
    events: List[Dict[str, Any]] = []
    for event_id in range(1, 11):
        events.append(
            {
                "event_id": event_id,
                "timestamp": datetime.utcnow().isoformat(),
                "payload": f"synthetic event payload {event_id}",
            }
        )
    return events


@app.function(image=image)
def producer() -> int:
    events = _generate_events()
    for event in events:
        queue.put(event)
    return len(events)


@app.function(image=image, volumes={"/events": volume})
def consumer() -> int:
    processed: List[Dict[str, Any]] = []
    while True:
        try:
            event = queue.get(timeout=1)
        except Exception:
            break
        if event is None:
            break
        payload = event.get("payload", "")
        event["processed"] = True
        event["word_count"] = len(payload.split())
        processed.append(event)

    with open(OUTPUT_PATH, "w", encoding="utf-8") as handle:
        json.dump(processed, handle, indent=2)

    volume.commit()
    return len(processed)


@app.function(image=image)
@modal.fastapi_endpoint(method="GET")
def status() -> Dict[str, Any]:
    keys = [
        "events_produced",
        "events_consumed",
        "processing_complete",
        "output_path",
    ]
    return {key: status_dict.get(key) for key in keys}


@app.local_entrypoint()
def main() -> None:
    produced = producer.remote()
    consumed = consumer.remote()
    status_dict["events_produced"] = produced
    status_dict["events_consumed"] = consumed
    status_dict["processing_complete"] = "true"
    status_dict["output_path"] = OUTPUT_PATH
    print(f"Produced: {produced} events")
    print(f"Consumed: {consumed} events")
    print(f"Output: {OUTPUT_PATH}")
